// Route each lead to the right email template.
// Full email copy lives in docs/lead-system/emails.md; replace the short
// defaults below with that copy (converted to HTML) when ready.
const BOOKING_URL = 'https://calendly.com/creative-remotelyavailable/30min';
const YT = 'https://youtube.com/@agenticali';

const raw = $input.first().json;
const body = raw.body || raw;
const name = (body.name || 'there').split(' ')[0];
const email = body.email || '';
const source = body.source || 'unknown';
const painPoint = body.painPoint || '';
const timestamp = body.timestamp || new Date().toISOString();

const sign = `<p>Ali Ameen<br>Founder, RemotelyAvailable<br><a href="${YT}">AI educator to 50,000+ students on YouTube</a></p>`;
const cta = `<p><a href="${BOOKING_URL}"><strong>Book your free 30-minute call</strong></a> (no commitment, no hard sell)</p>`;

const FIVE = {
  key: 'five-automations',
  subject: `${name}, here are the 5 automations most teams launch first`,
  html: `<p>Hi ${name},</p><p>Here are the five automations most teams start with: 1) lead replies within 60 seconds, 2) missed-call text-back, 3) invoice chasing that never forgets, 4) review collection on autopilot, 5) a Monday morning numbers email. Any one of them can be live inside two weeks.</p>${cta}${sign}`
};

const AUDIT = {
  key: 'local-audit',
  subject: `${name}, your free growth audit (3 quick questions)`,
  html: `<p>Hi ${name},</p><p>Thanks for requesting your free audit. Reply with: 1) your website address, 2) what you sell in one sentence, 3) the task that eats most of your team's week. Within 24 hours you'll get an honest audit: what's costing you enquiries, the automation we'd build first, and what it would save you monthly.</p>${cta}${sign}`
};

const FIXES = {
  'emails': { key: 'fix-emails', subject: `${name}, your plan for an inbox that answers itself`, html: `<p>Hi ${name},</p><p>Three fixes for an overflowing inbox: an AI first-responder that replies within 60 seconds, automatic inbox triage, and a website chatbot that deflects the questions before they become emails. Teams typically reclaim 10-15 hours a week.</p>${cta}${sign}` },
  'invoices': { key: 'fix-invoices', subject: `${name}, your plan for paperwork that files itself`, html: `<p>Hi ${name},</p><p>Three fixes for admin overload: auto-generated invoices when a job completes, polite relentless payment chasing (day 3, day 10, flag at 14), and AI document filing. Most businesses recover 5-15% of quietly unpaid revenue.</p>${cta}${sign}` },
  'missed-calls': { key: 'fix-missed-calls', subject: `${name}, your plan for a phone line that never misses`, html: `<p>Hi ${name},</p><p>Three fixes, rising in power: missed-call text-back (live in days), a 24/7 AI voice agent that answers and books (this recovered $1.2M/year for a logistics client), and automatic day 1/3/7 follow-up sequences.</p>${cta}${sign}` },
  'content': { key: 'fix-content', subject: `${name}, your plan for a content engine that posts weekly`, html: `<p>Hi ${name},</p><p>Inconsistent content is a systems problem: a repurposing pipeline that turns one voice note into a week of posts, a calendar that fills itself, and approve-from-your-phone publishing. From "when we remember" to 5+ posts a week.</p>${cta}${sign}` },
  'leads': { key: 'fix-leads', subject: `${name}, your plan for leads that qualify themselves`, html: `<p>Hi ${name},</p><p>The system: instant lead scoring against your ideal-client rules, smart routing (hot leads ping your phone with context), and an automatic follow-up machine. Our SaaS client booked 40% more demos in month one with this.</p>${cta}${sign}` },
  'other': { key: 'fix-other', subject: `${name}, let's find your biggest automation win`, html: `<p>Hi ${name},</p><p>Your biggest drain isn't on our standard list, which makes it interesting. On a free 30-minute call we walk through a normal week and shortlist the repetitive, rule-based, high-volume tasks: that's where automation pays back fastest. You leave with a written plan either way.</p>${cta}${sign}` }
};

let template;
if (source === 'website-lead-popup') {
  template = FIXES[painPoint] || FIXES['other'];
} else if (source.startsWith('location-page') || source.startsWith('location-hub')) {
  template = AUDIT;
} else {
  template = FIVE;
}

return [{
  json: {
    timestamp,
    name: body.name || '',
    email,
    source,
    painPoint,
    template: template.key,
    subject: template.subject,
    html: template.html
  }
}];

